-- MBL Catering — Pastry / cake shop setup (idempotent). Run in Supabase SQL editor.
alter table recipes add column if not exists place_id text references places(id) on delete cascade;

-- wipe the shop place's own data (recipes + menus/people/subscribers/settings)
delete from recipes where place_id in (select id from places where type='shop');
delete from menu_days where place_id in (select id from places where type='shop');
delete from people where place_id in (select id from places where type='shop');
delete from subscribers where place_id in (select id from places where type='shop');
delete from settings where place_id in (select id from places where type='shop');

-- 20 cake-shop products, owned by the shop place
